#!/usr/bin/env dotnet
// Find the earliest Friday the 13th in the proleptic Gregorian calendar (starting 0001-01-01)
// and count how many Friday the 13ths exist in a full 400-year cycle.

// Find earliest Friday the 13th starting from year 1
DateOnly date = new DateOnly(1, 1, 13); // start checking the 13th of each month
DateOnly? earliest = null;

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            earliest ??= d;
        }
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");
Console.WriteLine();

// Count Friday the 13ths in a full 400-year cycle (years 1–400)
int count = 0;
var dayCounts = new Dictionary<DayOfWeek, int>();
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    dayCounts[dow] = 0;

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        dayCounts[d.DayOfWeek]++;
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine();
Console.WriteLine("Distribution of the 13th by day of week:");
foreach (var (dow, c) in dayCounts.OrderByDescending(kv => kv.Value))
{
    Console.WriteLine($"  {dow,-9}: {c}");
}
EOF
